 gro_death <- gro_death |> 
   filter(str_detect(Cause, "^[A-Z\\-]+\\."))     # exclude Roman numeral headers

 count(gro_death,Cause)
 
 gro_death <- gro_death |> 
   mutate(cause_type = case_when(                                                            
Cause == 'II. NEOPLASMS (C00-D48)'                                                                        ~ 'modelled',
Cause == 'III. DISEASES OF THE BLOOD AND BLOOD-FORMING ORGANS AND CERTAIN  DISORDERS INVOLVING THE IMMUNE MECHANISM (D50-D89)'     ~ 'modelled',
Cause == 'IV. ENDOCRINE, NUTRITIONAL AND METABOLIC DISEASES (E00-E90)'                                    ~ 'modelled',
Cause == 'IX. DISEASES OF THE CIRCULATORY SYSTEM (I00-I99)'                ~ 'modelled',
Cause == 'VI-VIII. DISEASES OF THE NERVOUS SYSTEM AND THE SENSE ORGANS (G00-H95)'                         ~ 'other',
Cause == 'X. DISEASES OF THE RESPIRATORY SYSTEM (J00-J99)'  ~ 'other',
Cause == 'I. CERTAIN INFECTIOUS AND PARASITIC DISEASES (A00-B99)'                                         ~ 'other',
Cause == 'XI. DISEASES OF THE DIGESTIVE SYSTEM (K00-K93)'                                                 ~ 'other',
Cause == 'XII. DISEASES OF THE SKIN AND SUBCUTANEOUS TISSUE (L00-L99)'                                    ~ 'other',
Cause == 'XIII. DISEASES OF THE MUSCULOSKELETAL SYSTEM AND CONNECTIVE TISSUE (M00-M99)'                   ~ 'other',
Cause == 'XIV. DISEASES OF THE GENITOURINARY SYSTEM (N00-N99)'                                            ~ 'other',
Cause == 'XV. PREGNANCY, CHILDBIRTH AND THE PUERPERIUM (O00-O99)'                                         ~ 'other',
Cause == 'XVI. CERTAIN CONDITIONS ORIGINATING IN THE PERINATAL PERIOD (P00-P96)'                          ~ 'other',
Cause == 'XVII. CONGENITAL MALFORMATIONS, DEFORMATIONS AND CHROMOSOMAL ABNORMALITIES (Q00-Q99)'           ~ 'other',
Cause == 'V. MENTAL AND BEHAVIOURAL DISORDERS (F00-F99)'                                                  ~ 'other',
Cause == 'XVIII. SYSTEMS, SIGNS AND ABNORMAL CLINICAL AND LABORATORY FINDINGS, N.E.C. (R00-R99)'~ 'other',
Cause == 'XIX. EXTERNAL CAUSES OF Death'                                                                  ~ 'other',
   ))
 
 gro_death |> 
   count(cause_type,wt = `2023`)
 